SELECT EXTRACT(YEAR FROM o_orderdate) AS o_year, SUM(CASE WHEN n2.n_name = 'GERMANY' THEN l_extendedprice * (1 - l_discount) ELSE 0 END) / SUM(l_extendedprice * (1 - l_discount)) AS mkt_share FROM customer, orders, lineitem, supplier, nation n1, nation n2, region WHERE c_custkey = o_custkey AND l_orderkey = o_orderkey AND l_suppkey = s_suppkey AND c_nationkey = n1.n_nationkey AND s_nationkey = n1.n_nationkey AND n1.n_regionkey = r_regionkey AND r_name = 'EUROPE' AND n2.n_name = 'GERMANY' AND o_orderdate >= '1995-01-01' AND o_orderdate < '1996-12-31' GROUP BY EXTRACT(YEAR FROM o_orderdate) ORDER BY o_year;